### Scenario 2: Multi-Session Memory Isolation
```typescript
describe("Integration: Multi-session memory isolation", () => {
  it("should not leak memory between sessions", async () => {
    const driver = createRealDriver({ maxHistoryMessages: 20 });

    global.gc && global.gc();
    const beforeSessions = process.memoryUsage().heapUsed;

    // Create and destroy 10 sessions
    for (let s = 0; s < 10; s++) {
      const session = await driver.createSession({ task: `Session ${s}` });

      // Fill session with messages
      for (let i = 0; i < 50; i++) {
        await session.addMessage({ role: "user", content: `S${s}-M${i}` });
      }

      // Destroy session
      await driver.destroySession(session.id);
      console.log(`[INTEG] Session ${s} created, filled, destroyed`);
    }

    global.gc && global.gc();
    const afterSessions = process.memoryUsage().heapUsed;
    const leak = afterSessions - beforeSessions;

    console.log(`[INTEG] Memory before: ${(beforeSessions / 1024 / 1024).toFixed(2)} MB`);
    console.log(`[INTEG] Memory after: ${(afterSessions / 1024 / 1024).toFixed(2)} MB`);
    console.log(`[INTEG] Potential leak: ${(leak / 1024 / 1024).toFixed(2)} MB`);

    // Should not have significant memory retained after session destruction
    expect(leak).toBeLessThan(5 * 1024 * 1024);  // < 5 MB
    console.log("[INTEG] PASS: No significant memory leak between sessions");
  });
});
```

### Scenario 3: Token Counter Performance
```typescript
describe("Integration: Token counting performance", () => {
  it("should count tokens efficiently for pruning decisions", async () => {
    const driver = createRealDriver({ 
      maxHistoryMessages: 1000,
      maxHistoryTokens: 10000,  // Token limit will trigger first
    });

    const session = await driver.createSession({ task: "Token test" });
    const startTime = performance.now();

    // Add messages until token limit triggers
    for (let i = 0; i < 100; i++) {
      await session.addMessage({
        role: "user",
        content: "x".repeat(500),  // ~125 tokens each
      });
    }

    const elapsed = performance.now() - startTime;
    console.log(`[INTEG] 100 messages with token counting: ${elapsed.toFixed(2)} ms`);

    // Token counting + pruning should be fast
    expect(elapsed).toBeLessThan(5000);  // < 5 seconds for 100 messages

    // Verify token limit was enforced
    const estimatedTokens = session.conversationHistory.reduce(
      (sum, m) => sum + Math.ceil((m.content as string).length / 4),
      0
    );
    console.log(`[INTEG] Estimated remaining tokens: ${estimatedTokens}`);
    expect(estimatedTokens).toBeLessThanOrEqual(12000);  // Some buffer
  });
});
